/**
 * Tests for StockMediaService
 * @module stock-media.test
 */

import {
  clearStockMediaCache,
  getStockMediaCacheSize,
  getAvailableProviders,
  getProviderRateLimit,
  formatAttribution,
  getProviderUrl,
  stockMediaToCanvasData,
  searchStockMedia,
  searchAllProviders,
  _mapLocaleToPixabay,
  type StockMediaItem,
  type StockSearchParams,
} from '@/lib/media/stock-media';

// ============================================================================
// MOCK SETUP
// ============================================================================

// Mock logger
jest.mock('@/lib/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

// Store original env
const originalEnv = { ...process.env };

// Mock fetch globally
const mockFetch = jest.fn();
global.fetch = mockFetch;

beforeEach(() => {
  jest.clearAllMocks();
  clearStockMediaCache();
  mockFetch.mockReset();
  // Reset env
  process.env = { ...originalEnv };
  delete process.env.PEXELS_API_KEY;
  delete process.env.PIXABAY_API_KEY;
});

afterAll(() => {
  process.env = originalEnv;
});

