function setupPexelsMock() {
  process.env.PEXELS_API_KEY = 'test-pexels-key';

  mockFetch.mockImplementation((url: string) => {
    const headers = new Map();
    headers.set('x-ratelimit-remaining', '199');
    headers.set('x-ratelimit-limit', '200');

    if (url.includes('api.pexels.com/v1/search')) {
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve(mockPexelsImageResponse()),
        headers: { get: (h: string) => headers.get(h) },
      });
    }
    if (url.includes('api.pexels.com/videos/search')) {
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve(mockPexelsVideoResponse()),
        headers: { get: (h: string) => headers.get(h) },
      });
    }
    return Promise.resolve({ ok: false, status: 404, headers: { get: () => null } });
  });
}

function setupPixabayMock() {
  process.env.PIXABAY_API_KEY = 'test-pixabay-key';

  mockFetch.mockImplementation((url: string) => {
    const headers = new Map();
    headers.set('x-ratelimit-remaining', '99');

    if (url.includes('pixabay.com/api/videos')) {
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve(mockPixabayVideoResponse()),
        headers: { get: (h: string) => headers.get(h) },
      });
    }
    if (url.includes('pixabay.com/api/')) {
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve(mockPixabayImageResponse()),
        headers: { get: (h: string) => headers.get(h) },
      });
    }
    return Promise.resolve({ ok: false, status: 404, headers: { get: () => null } });
  });
}

// ============================================================================
// TESTS
// ============================================================================

describe('Stock Media Service', () => {
  // --------------------------------------------------------------------------
  // Cache
  // --------------------------------------------------------------------------
  describe('Cache', () => {
    it('starts empty', () => {
      expect(getStockMediaCacheSize()).toBe(0);
    });

    it('clearStockMediaCache empties cache', () => {
      // We need to populate cache first via a search
      clearStockMediaCache();
      expect(getStockMediaCacheSize()).toBe(0);
    });
  });

  // --------------------------------------------------------------------------
  // Provider availability
  // --------------------------------------------------------------------------
  describe('getAvailableProviders', () => {
    it('returns empty when no keys set', () => {
      const providers = getAvailableProviders();
      expect(providers).toEqual([]);
    });

    it('returns pexels when PEXELS_API_KEY is set', () => {
      process.env.PEXELS_API_KEY = 'test-key';
      const providers = getAvailableProviders();
      expect(providers).toContain('pexels');
    });

    it('returns pixabay when PIXABAY_API_KEY is set', () => {
      process.env.PIXABAY_API_KEY = 'test-key';
      const providers = getAvailableProviders();
      expect(providers).toContain('pixabay');
    });

    it('returns both when both keys set', () => {
      process.env.PEXELS_API_KEY = 'test-key';
      process.env.PIXABAY_API_KEY = 'test-key';
      const providers = getAvailableProviders();
      expect(providers).toHaveLength(2);
      expect(providers).toContain('pexels');
      expect(providers).toContain('pixabay');
    });
  });

  // --------------------------------------------------------------------------
  // Rate limit
  // --------------------------------------------------------------------------
  describe('getProviderRateLimit', () => {
    it('returns default rate limit for pexels', () => {
      const status = getProviderRateLimit('pexels');
      expect(status.limit).toBe(200);
      expect(status.remaining).toBeGreaterThanOrEqual(0);
    });

    it('returns default rate limit for pixabay', () => {
      const status = getProviderRateLimit('pixabay');
      expect(status.limit).toBe(100);
    });
  });

  // --------------------------------------------------------------------------
  // formatAttribution
  // --------------------------------------------------------------------------
  describe('formatAttribution', () => {
    const baseItem: StockMediaItem = {
      id: 'test-1',
      title: 'Test Photo',
      type: 'image',
      thumbnail: '',
      previewUrl: '',
      downloadUrl: '',
      source: 'pexels',
      author: 'John Doe',
      authorUrl: '',
      sourceUrl: '',
      license: { type: 'Pexels License', attributionRequired: false, attributionText: '', detailsUrl: '' },
      width: 1920,
      height: 1080,
    };

    it('formats pexels attribution', () => {
      expect(formatAttribution(baseItem)).toBe('Photo by John Doe on Pexels');
    });

    it('formats pixabay attribution', () => {
      expect(formatAttribution({ ...baseItem, source: 'pixabay' })).toBe('John Doe on Pixabay');
    });
  });

  // --------------------------------------------------------------------------
  // getProviderUrl
  // --------------------------------------------------------------------------
  describe('getProviderUrl', () => {
    it('returns pexels URL', () => {
      expect(getProviderUrl('pexels')).toBe('https://www.pexels.com');
    });

    it('returns pixabay URL', () => {
      expect(getProviderUrl('pixabay')).toBe('https://pixabay.com');
    });
  });

  // --------------------------------------------------------------------------
  // stockMediaToCanvasData
  // --------------------------------------------------------------------------
  describe('stockMediaToCanvasData', () => {
    it('converts stock item to canvas format', () => {
      const item: StockMediaItem = {
        id: 'test-1',
        title: 'Office Photo',
        type: 'image',
        thumbnail: 'thumb.jpg',
        previewUrl: 'preview.jpg',
        downloadUrl: 'download.jpg',
        source: 'pexels',
        author: 'Photographer',
        authorUrl: 'https://pexels.com/@photographer',
        sourceUrl: 'https://pexels.com/photo/1',
        license: { type: 'Pexels License', attributionRequired: false, attributionText: '', detailsUrl: '' },
        width: 1920,
        height: 1080,
      };

      const result = stockMediaToCanvasData(item);
      expect(result.type).toBe('image');
      expect(result.name).toBe('Office Photo');
      expect(result.url).toBe('download.jpg');
      expect(result.width).toBe(1920);
      expect(result.height).toBe(1080);
      expect(result.attribution).toBe('Photo by Photographer on Pexels');
      expect(result.source).toBe('pexels');
    });

    it('falls back to previewUrl when downloadUrl is empty', () => {
      const item: StockMediaItem = {
        id: 'test-2',
        title: 'Video',
        type: 'video',
        thumbnail: 'thumb.jpg',
        previewUrl: 'preview.mp4',
        downloadUrl: '',
        source: 'pixabay',
        author: 'Author',
        authorUrl: '',
        sourceUrl: '',
        license: { type: 'Pixabay License', attributionRequired: false, attributionText: '', detailsUrl: '' },
        width: 0,
        height: 0,
      };

      const result = stockMediaToCanvasData(item);
      expect(result.url).toBe('preview.mp4');
      expect(result.width).toBe(1920); // default fallback
      expect(result.height).toBe(1080);
    });
  });

  // --------------------------------------------------------------------------
  // mapLocaleToPixabay
  // --------------------------------------------------------------------------
  describe('_mapLocaleToPixabay', () => {
    it('maps pt-BR to pt', () => {
      expect(_mapLocaleToPixabay('pt-BR')).toBe('pt');
    });

    it('maps en-US to en', () => {
      expect(_mapLocaleToPixabay('en-US')).toBe('en');
    });

    it('defaults to en for unknown locales', () => {
      expect(_mapLocaleToPixabay('xyz')).toBe('en');
    });

    it('maps es to es', () => {
      expect(_mapLocaleToPixabay('es')).toBe('es');
    });
  });

  // --------------------------------------------------------------------------
  // searchStockMedia — Pexels provider
  // --------------------------------------------------------------------------
  describe('searchStockMedia — Pexels', () => {
    it('returns images from Pexels', async () => {
      setupPexelsMock();

      const result = await searchStockMedia({ query: 'office' });
      expect(result.items.length).toBeGreaterThan(0);
      expect(result.provider).toBe('pexels');
      expect(result.query).toBe('office');

      // Check image items
      const images = result.items.filter(i => i.type === 'image');
      expect(images.length).toBe(2);
      expect(images[0].id).toBe('pexels-100');
      expect(images[0].author).toBe('John Doe');
      expect(images[0].source).toBe('pexels');
      expect(images[0].license.type).toBe('Pexels License');
    });

    it('returns videos from Pexels', async () => {
      setupPexelsMock();

      const result = await searchStockMedia({ query: 'nature', type: 'video' });
      expect(result.items.length).toBe(1);
      expect(result.items[0].type).toBe('video');
      expect(result.items[0].id).toBe('pexels-v-200');
      expect(result.items[0].duration).toBe(30);
    });

    it('returns both images and videos when type=all', async () => {
      setupPexelsMock();

      const result = await searchStockMedia({ query: 'test', type: 'all' });
      const types = new Set(result.items.map(i => i.type));
      expect(types.has('image')).toBe(true);
      expect(types.has('video')).toBe(true);
    });

    it('caches results', async () => {
      setupPexelsMock();

      const result1 = await searchStockMedia({ query: 'office', type: 'image' });
      expect(result1.cached).toBe(false);
      expect(getStockMediaCacheSize()).toBe(1);

      const result2 = await searchStockMedia({ query: 'office', type: 'image' });
      expect(result2.cached).toBe(true);
      // fetch should only be called once (from first search)
      expect(mockFetch).toHaveBeenCalledTimes(1);
    });

    it('passes orientation param to Pexels', async () => {
      setupPexelsMock();

      await searchStockMedia({ query: 'landscape', type: 'image', orientation: 'landscape' });
      expect(mockFetch).toHaveBeenCalledWith(
        expect.stringContaining('orientation=landscape'),
        expect.objectContaining({ headers: { Authorization: 'test-pexels-key' } }),
      );
    });

    it('passes locale param to Pexels', async () => {
      setupPexelsMock();

      await searchStockMedia({ query: 'test', type: 'image', locale: 'pt-BR' });
      expect(mockFetch).toHaveBeenCalledWith(
        expect.stringContaining('locale=pt-BR'),
        expect.any(Object),
      );
    });
  });

  // --------------------------------------------------------------------------
  // searchStockMedia — Pixabay provider
  // --------------------------------------------------------------------------
  describe('searchStockMedia — Pixabay', () => {
    it('returns images from Pixabay', async () => {
      setupPixabayMock();

      const result = await searchStockMedia({ query: 'office' });
      expect(result.items.length).toBeGreaterThan(0);
      expect(result.provider).toBe('pixabay');

      const images = result.items.filter(i => i.type === 'image');
      expect(images.length).toBe(2);
      expect(images[0].id).toBe('pixabay-300');
      expect(images[0].title).toBe('office');
      expect(images[0].source).toBe('pixabay');
      expect(images[0].license.type).toBe('Pixabay Content License');
    });

    it('returns videos from Pixabay', async () => {
      setupPixabayMock();

      const result = await searchStockMedia({ query: 'nature', type: 'video' });
      const videos = result.items.filter(i => i.type === 'video');
      expect(videos.length).toBe(1);
      expect(videos[0].id).toBe('pixabay-v-400');
      expect(videos[0].duration).toBe(15);
    });

    it('includes tags from Pixabay results', async () => {
      setupPixabayMock();

      const result = await searchStockMedia({ query: 'office', type: 'image' });
      expect(result.items[0].tags).toBeDefined();
      expect(result.items[0].tags).toContain('office');
      expect(result.items[0].tags).toContain('work');
    });
  });

  // --------------------------------------------------------------------------
  // searchStockMedia — Fallback behavior
  // --------------------------------------------------------------------------
  describe('searchStockMedia — Fallback', () => {
    it('falls back to Pixabay when Pexels fails', async () => {
      process.env.PEXELS_API_KEY = 'bad-key';
      process.env.PIXABAY_API_KEY = 'good-key';

      mockFetch.mockImplementation((url: string) => {
        const headers = new Map();
        headers.set('x-ratelimit-remaining', '99');

        if (url.includes('pexels.com')) {
          return Promise.resolve({
            ok: false,
            status: 403,
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        if (url.includes('pixabay.com/api/videos')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve(mockPixabayVideoResponse()),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        if (url.includes('pixabay.com/api/')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve(mockPixabayImageResponse()),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        return Promise.resolve({ ok: false, status: 404, headers: { get: () => null } });
      });

      const result = await searchStockMedia({ query: 'test', type: 'image' });
      // Pexels returned no items, so service tries Pixabay
      expect(result.provider).toBe('pixabay');
      expect(result.items.length).toBe(2);
    });

    it('returns empty when no providers configured', async () => {
      const result = await searchStockMedia({ query: 'test' });
      expect(result.items).toEqual([]);
      expect(result.total).toBe(0);
    });

    it('uses preferred provider when specified', async () => {
      process.env.PEXELS_API_KEY = 'pexels-key';
      process.env.PIXABAY_API_KEY = 'pixabay-key';

      mockFetch.mockImplementation((url: string) => {
        const headers = new Map();
        headers.set('x-ratelimit-remaining', '99');

        if (url.includes('pixabay.com/api/videos')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve(mockPixabayVideoResponse()),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        if (url.includes('pixabay.com/api/')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve(mockPixabayImageResponse()),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        return Promise.resolve({ ok: false, status: 404, headers: { get: () => null } });
      });

      const result = await searchStockMedia({ query: 'test', type: 'image' }, 'pixabay');
      expect(result.provider).toBe('pixabay');
      expect(result.items.length).toBe(2);
    });
  });

  // --------------------------------------------------------------------------
  // searchAllProviders
  // --------------------------------------------------------------------------
  describe('searchAllProviders', () => {
    it('returns empty when no providers configured', async () => {
      const result = await searchAllProviders({ query: 'test' });
      expect(result.items).toEqual([]);
    });

    it('fetches from all configured providers in parallel', async () => {
      process.env.PEXELS_API_KEY = 'pexels-key';
      process.env.PIXABAY_API_KEY = 'pixabay-key';

      mockFetch.mockImplementation((url: string) => {
        const headers = new Map();
        headers.set('x-ratelimit-remaining', '199');

        if (url.includes('api.pexels.com/v1/search')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve(mockPexelsImageResponse()),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        if (url.includes('api.pexels.com/videos/search')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve({ total_results: 0, videos: [] }),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        if (url.includes('pixabay.com/api/videos')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve({ totalHits: 0, hits: [] }),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        if (url.includes('pixabay.com/api/')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve(mockPixabayImageResponse()),
            headers: { get: (h: string) => headers.get(h) },
          });
        }
        return Promise.resolve({ ok: false, status: 404, headers: { get: () => null } });
      });

      const result = await searchAllProviders({ query: 'test', type: 'image' });
      // Should have results from both providers interleaved
      expect(result.items.length).toBe(4); // 2 pexels + 2 pixabay
      const sources = new Set(result.items.map(i => i.source));
      expect(sources.has('pexels')).toBe(true);
      expect(sources.has('pixabay')).toBe(true);
    });
  });

  // --------------------------------------------------------------------------
  // Error handling
  // --------------------------------------------------------------------------
  describe('Error handling', () => {
    it('handles fetch timeout gracefully', async () => {
      process.env.PEXELS_API_KEY = 'test-key';

      mockFetch.mockImplementation(() => {
        return new Promise((_, reject) => {
          setTimeout(() => reject(new Error('AbortError')), 50);
        });
      });

      const result = await searchStockMedia({ query: 'test', type: 'image' });
      // Should not throw, just return empty
      expect(result.items).toEqual([]);
    });

    it('handles network error gracefully', async () => {
      process.env.PEXELS_API_KEY = 'test-key';

      mockFetch.mockRejectedValue(new Error('Network error'));

      const result = await searchStockMedia({ query: 'test', type: 'image' });
      expect(result.items).toEqual([]);
    });

    it('handles malformed JSON response', async () => {
      process.env.PEXELS_API_KEY = 'test-key';

      mockFetch.mockResolvedValue({
        ok: true,
        json: () => Promise.reject(new Error('Invalid JSON')),
        headers: { get: () => null },
      });

      const result = await searchStockMedia({ query: 'test', type: 'image' });
      expect(result.items).toEqual([]);
    });
  });

  // --------------------------------------------------------------------------
  // Pagination
  // --------------------------------------------------------------------------
  describe('Pagination', () => {
    it('passes page and perPage to provider', async () => {
      setupPexelsMock();

      await searchStockMedia({ query: 'test', type: 'image', page: 2, perPage: 10 });
      expect(mockFetch).toHaveBeenCalledWith(
        expect.stringContaining('page=2'),
        expect.any(Object),
      );
      expect(mockFetch).toHaveBeenCalledWith(
        expect.stringContaining('per_page=10'),
        expect.any(Object),
      );
    });

    it('defaults to page 1 and perPage 20', async () => {
      setupPexelsMock();

      const result = await searchStockMedia({ query: 'test', type: 'image' });
      expect(result.page).toBe(1);
      expect(result.perPage).toBe(20);
    });
  });
});
